import {type KeyboardEventHandler, useEffect, useRef, useState} from "react";
import KitsInputText from "../../../../form/inputs/InputText";
import {type FilterEl} from "../Filter";


const TextFilter: FilterEl<{ debounceFilterWaitTime: number; filterMode: 'enter' | 'debounce' }> = ({
    debounceFilterWaitTime,
    filterMode,
    ...options
}) => {
    const [value, setValue] = useState<string>('');
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Sync external filter value → local state (reset / clear support)
    useEffect(() => {
        if (options.filterModel && 'value' in options.filterModel) {
            const v = options.filterModel.value;
            setValue(typeof v === 'string' ? v : '');
        }
    }, [options.filterModel]);

    const applyFilter = (val: string) => {
        if (debounceRef.current) clearTimeout(debounceRef.current);
        options.filterApplyCallback(val);
    };

    const onChange = (e: any) => {
        const newValue = e.target?.value ?? e ?? '';
        setValue(newValue);

        if (filterMode === 'debounce') {
            if (debounceRef.current) clearTimeout(debounceRef.current);
            if (newValue) {
                debounceRef.current = setTimeout(() => {
                    options.filterApplyCallback(newValue);
                }, debounceFilterWaitTime);
            }
        }
    };

    useEffect(() => {
        return () => {
            if (debounceRef.current) clearTimeout(debounceRef.current);
        };
    }, []);

    return (
        <KitsInputText
            attached
            id="filter-text"
            value={value}
            onChange={onChange}
            onKeyDown={((event: any) => {
                if (event.key === 'Enter') applyFilter(value);
            }) as any}
            onBlur={() => applyFilter(value)}
            inputSize="sm"
            localProps={{style: {width: '100%'}}}
        />
    );
};

export default TextFilter;
